const EventEmitter = require('events');

class OrderSystem extends EventEmitter {
  constructor() {
    super();
    this.orders = [];
  }

  placeOrder(item, quantity) {
    const order = { id: Date.now(), item, quantity };
    this.orders.push(order);
    this.emit('orderPlaced', order);
    return order;
  }

  shipOrder(orderId) {
    const order = this.orders.find(o => o.id === orderId);
    if (order) {
      this.emit('orderShipped', order);
    }
  }
}

const shop = new OrderSystem();

shop.on('orderPlaced', (order) => {
  console.log(`Order placed: ${order.item} x${order.quantity}`);
});

shop.on('orderShipped', (order) => {
  console.log(`Order ${order.id} has been shipped!`);
});

const myOrder = shop.placeOrder('Laptop', 1);
shop.shipOrder(myOrder.id);

